import{_ as o,c as i,o as l,ae as a}from"./chunks/framework.Cqi9LMMK.js";const p=JSON.parse('{"title":"Релиз 2.3.0","description":"","frontmatter":{"title":"Релиз 2.3.0"},"headers":[],"relativePath":"ru/releases/2.3.0.md","filePath":"ru/releases/2.3.0.md"}'),c={name:"ru/releases/2.3.0.md"};function d(t,e,r,s,n,u){return l(),i("div",null,[...e[0]||(e[0]=[a('<h2 id="_2-3-0-2026-03-16" tabindex="-1">[2.3.0] - 2026-03-16 <a class="header-anchor" href="#_2-3-0-2026-03-16" aria-label="Permalink to &quot;[2.3.0] - 2026-03-16&quot;">​</a></h2><h3 id="network" tabindex="-1">Network <a class="header-anchor" href="#network" aria-label="Permalink to &quot;Network&quot;">​</a></h3><ul><li>Добавлена генерация <strong>Postman</strong>-коллекций на основе запросов, собранных во вкладке <code>Network</code>.</li><li>В однопанельном режиме кнопка <code>Copy cURL</code> заменена контекстным меню с доступом к: <ul><li><code>Breakpoint</code></li><li><code>Mock</code></li><li><code>Copy cURL</code></li></ul></li><li>Добавлена логика вызова контекстного меню (ПКМ) по шапке детализации запроса.</li></ul><hr><h3 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h3><ul><li>Исправлена работа избранного и чёрного списка при работе с <code>Props</code>.</li><li>Изменена логика сбора данных с учетом <code>blacklist</code>: игнорируемые элементы исключаются на этапе предварительного обхода, а не только скрываются из таблицы, что ускоряет загрузку вкладки.</li><li>Добавлено меню быстрых действий для <code>Props</code>.</li><li>Добавлена возможность обновления открытого компонента в режиме чтения.</li><li>Добавлены shortcut-переходы к списку избранного при нажатии на счётчик избранных элементов.</li></ul><hr><h3 id="store" tabindex="-1">Store <a class="header-anchor" href="#store" aria-label="Permalink to &quot;Store&quot;">​</a></h3><ul><li>Добавлен функционал избранного для <code>Pinia Store</code> включая shortcut-переход.</li><li>Добавлено меню быстрых действий для <code>Pinia Store</code>.</li><li>Добавлена возможность обновления открытого элемента в режиме чтения.</li><li>В разделе <code>Options</code> доступно создание и редактирование пользовательских избранных элементов, включая поддержку <code>wildcards</code>.</li></ul><hr><h3 id="options" tabindex="-1">Options <a class="header-anchor" href="#options" aria-label="Permalink to &quot;Options&quot;">​</a></h3><ul><li>Изменён алгоритм хранения пользовательских настроек: выбранные файлы теперь сохраняются как локальные копии в хранилище приложения.</li><li><code>Standalone</code>-версия переведена на собственное локальное хранилище. Настройки сохраняются между запусками и доступны на разных сайтах без потери данных.</li><li>Режим tree временно отключён — работа с JSON доступна только в text-режиме.</li></ul><h4 id="customize" tabindex="-1">Customize <a class="header-anchor" href="#customize" aria-label="Permalink to &quot;Customize&quot;">​</a></h4><p>В разделе <code>Options → General → Customize</code> добавлены настройки визуального оформления приложения:</p><ul><li><code>Dark / Light</code> — цветовая схема;</li><li><code>Image</code> — фон (<code>File / Link</code>) с поддержкой: <ul><li>статичных изображений,</li><li><code>GIF</code>,</li><li><code>MP4</code>;</li></ul></li><li>Выбор файла через <code>Browse</code> или из списка ранее сохранённых;</li><li>Добавление файла по ссылке;</li><li><code>Image Opacity</code> — прозрачность;</li><li><code>Blur</code> — размытие;</li><li><code>Noise Intensity / Opacity</code> — параметры шумового слоя;</li><li><code>Position (X / Y)</code> — положение изображения;</li><li><code>Scale</code> — масштаб (<code>100–200%</code>).</li></ul><hr><h3 id="ui-ux" tabindex="-1">UI / UX <a class="header-anchor" href="#ui-ux" aria-label="Permalink to &quot;UI / UX&quot;">​</a></h3><ul><li>Добавлена адаптивная раскладка интерфейса для небольших экранов.</li><li>На широких экранах используется двухпанельный режим: список и детали отображаются одновременно.</li><li>При ширине около <code>1000px</code> интерфейс автоматически переключается в однопанельный режим.</li><li>Добавлена поддержка клавиши <code>Esc</code> для закрытия активных панелей и диалогов.</li><li>Добавлена поддержка поиска <code>Ctrl+F</code> в режиме вкладки <code>DevTools</code>.</li><li>Добавлены скелетоны загрузки для таблиц <code>Props</code> и <code>Pinia</code> вместо текста <code>Not found</code>.</li><li>Добавлены настройки отображения колонок для таблиц <code>Props</code>, <code>Pinia</code> и <code>Network</code>.</li><li>Изменён дизайн шеврона для открытия <code>iframe</code>.</li><li>Добавлена поддержка контекстного меню (ПКМ) при работе с таблицами.</li></ul><hr><h3 id="производительность" tabindex="-1">Производительность <a class="header-anchor" href="#производительность" aria-label="Permalink to &quot;Производительность&quot;">​</a></h3><ul><li>Изменена логика обработки <code>blacklist</code> во вкладке <code>Props</code>: заблокированные элементы больше не участвуют в предварительном обходе, что ускоряет сбор данных и загрузку вкладки.</li></ul><hr><h3 id="исправления" tabindex="-1">Исправления <a class="header-anchor" href="#исправления" aria-label="Permalink to &quot;Исправления&quot;">​</a></h3><ul><li>Исправлена область нажатия для блока <code>JSON</code> при редактировании во время скролла.</li><li>Исправлены зависания приложения при длительной работе вкладки <code>Network</code>.</li><li>Исправлено поведение <code>Ctrl+A</code> — выделение применяется только к активному полю ввода.</li><li>Исправлено отображение кнопок сброса и удаления в <code>disabled</code>-состоянии.</li><li>Исправлено отображение таблиц в <code>Options</code> при большом количестве значений.</li><li>Исправлены стили режима редактирования <code>JSON</code>.</li><li>Внесены косметические правки оформления.</li></ul>',24)])])}const m=o(c,[["render",d]]);export{p as __pageData,m as default};
